module zero_crossing_detector (
    input wire clk,
    input wire signal_in,
    output reg zero_cross
);
    reg anti_signal_prev;

    always @(posedge clk) begin
        zero_cross <= (signal_in ^ anti_signal_prev) && anti_signal_prev != signal_in;
        anti_signal_prev <= signal_in;
    end
endmodule
